    date: "2019-09-09",
    body: "<p><img alt=\"KakaoTalk_20190909_235842478.png\" src=\"assets/img/posts/2_1_1_1_39/2.png\" /></p> <p><img alt=\"KakaoTalk_20190909_235844750.png\" src=\"assets/img/posts/2_1_1_1_39/3.png\" /></p> <p><img alt=\"KakaoTalk_20190910_001132462.png\" src=\"assets/img/posts/2_1_1_1_39/4.png\" /></p> <p><img alt=\"KakaoTalk_20190910_001134891.png\" src=\"assets/img/posts/2_1_1_1_39/5.png\" /></p> <p><br /> </p>"
